                return (
                  <div
                    key={tab.id}
                    className={`absolute transition-all duration-500 ease-in-out rounded-2xl border-4 ${isActive ? 'border-gray-200' : 'border-gray-100'} ${isActive ? 'shadow-2xl' : 'shadow-md'}`}
